    LU: { kanton: 'LU', erlassName: 'Verordnung über die Beurkundungsgebühren (BeurkGebV)', erlassNr: 'SRL 258', artikel: '§ 19 Abs. 1', stand: '1. Januar 2022', verifiziert: R, quelleUrl: 'https://srl.lu.ch/api/de/versions/3870/pdf_file_with_annexes', hinweis: 'Rahmen/Aufwand, nicht nachlasswertbasiert. Frühere wertabhängige Buchstaben a-e in § 19 Abs. 1 wurden per 1.1.2022 aufgehoben.', regel: { typ: 'formel_extern', hinweis: 'Errichtung eines Erbvertrages (Art. 512 ZGB) bzw. öffentlicher letztwilliger Verfügung (Art. 499 ZGB): Gebühr Fr. 500.- bis Fr. 5000.-. Abänderung Fr. 150.- bis 2000.- (Abs. 2), Aufhebung Fr. 150.- bi' } },
