    GL: { kanton: 'GL', erlassName: 'Verordnung über Beurkundung und Beglaubigung mit Gebührentarif', erlassNr: 'GS III B/3/2', artikel: 'Art. A1-3', stand: '26.11.2008', verifiziert: R, quelleUrl: 'https://gesetze.gl.ch/app/de/texts_of_law/III%20B%2F3%2F2', hinweis: 'Kein Wert-/Nachlasswert-Tarif. Bei aussergewöhnlichem Aufwand zusätzlich Art. 11 Abs. 2.', regel: { typ: 'rahmen', vonChf: 100, bisChf: 1000 } },
    ZG: { kanton: 'ZG', erlassName: 'Kantonsratsbeschluss über die Gebühren in Verwaltungs- und Zivilsachen (Verwaltungsgebührentarif)', erlassNr: '641.1', artikel: '§ 9 Nr. 88', stand: '5.6.2025', verifiziert: R, quelleUrl: 'https://bgs.zg.ch/app/de/texts_of_law/641.1', hinweis: 'Erbvertrag (Art. 512 ZGB) und öffentliches Testament im gleichen Tatbestand zusammengefasst.', regel: { typ: 'rahmen', vonChf: 300, bisChf: 4000 } },
