    SO: { kanton: 'SO', erlassName: 'Gebührentarif (GT)', erlassNr: 'BGS 615.11', artikel: '§ 24 lit. a GT', stand: '1. März 2026 (Beschluss 11. November 202', verifiziert: R, quelleUrl: 'https://bgs.so.ch/app/de/texts_of_law/615.11', hinweis: 'Aufhebung 100-400 (§ 24 lit. c). Rahmentarif, kein Nachlasswert-Promille; Aufwand/Bedeutung massgebend (§ 3).', regel: { typ: 'rahmen', vonChf: 200, bisChf: 6000 } },
    BS: { kanton: 'BS', erlassName: 'Verordnung über den Notariatstarif', erlassNr: 'SG 292.400', artikel: '§ 11 Ziff. 8 i.V.m. Ziff. 2', stand: '1. Juli 2016', verifiziert: R, quelleUrl: 'https://www.gesetzessammlung.bs.ch/app/de/texts_of_law/292.400', hinweis: 'Bemessung im Rahmen nach § 5 (Interessewert, Aufwand). Inventar bei lebzeitiger Vermögensübertragung aus Erbvertrag separat nach Ziff. 10/3.', regel: { typ: 'rahmen', vonChf: 400, bisChf: 2000 } },
    BL: { kanton: 'BL', erlassName: 'Verordnung über die Notariatsgebühren (NotGebV)', erlassNr: 'SGS 217.13', artikel: '§9 Abs. 1 lit. a', stand: '1.11.2012', verifiziert: R, quelleUrl: 'https://bl.clex.ch/app/de/texts_of_law/217.13', hinweis: 'Erbvertrag ausdrücklich genannt. Kein Nachlasswert-Bezug. +MwSt.', regel: { typ: 'formel_extern', hinweis: 'Für Ehe- und Erbverträge sowie Vermögensverträge nach PartG: Rahmengebühr 500-1\'700 Fr.; Verrechnung nach Stundenansatz (§9 Abs. 2).' } },
