    GR: { kanton: 'GR', erlassName: 'Verordnung über die Notariatsgebühren (NotGebV)', erlassNr: 'BR 210.370', artikel: 'Art. 13 Abs. 1 lit. b NotGebV', stand: '1. Januar 2024', verifiziert: R, quelleUrl: 'https://www.gr-lex.gr.ch/api/de/versions/3348/pdf_file', hinweis: '1‰ nur auf den 200\'000 übersteigenden Vertragswert; Deckel 15\'000.', regel: { typ: 'promille', promille: 1, minChf: 500, maxChf: 15000 } },
