    VS: { kanton: 'VS', erlassName: 'Règlement fixant le tarif des émoluments et des débours des notaires', erlassNr: '178.104', artikel: 'Art. 16 al. 1 lit. c ch. 2 (pacte successoral, art. 512 CC)', stand: '26.11.2008', verifiziert: R, quelleUrl: 'https://lex.vs.ch/api/fr/versions/1413/pdf_file', hinweis: 'Rahmentarif 200-3000 CHF; Auflösung/Annullierung eines Erbvertrags separat 100-200 CHF (Art. 16 al. 1 lit. c ch. 6).', regel: { typ: 'rahmen', vonChf: 200, bisChf: 3000 } },
