    NE: { kanton: 'NE', erlassName: 'Arrêté fixant le tarif des émoluments des notaires', erlassNr: 'RSN 166.31', artikel: 'Art. 14 ch. 17 (Testament public)', stand: 'Etat au 13 mai 2015 (en vigueur depuis l', verifiziert: R, quelleUrl: 'https://rsn.ne.ch/DATA/program/books/RSN2015/20154/htm/16631.htm', regel: { typ: 'rahmen', vonChf: 150, bisChf: 2000 } },
    GE: { kanton: 'GE', erlassName: 'Règlement sur les émoluments des notaires (REmNot)', erlassNr: 'RSG E 6 05.03', artikel: 'Art. 18 al. 1 REmNot', stand: 'État au 30 avril 2015 (in Kraft, nicht a', verifiziert: R, quelleUrl: 'https://silgeneve.ch/legis/program/books/rsg/htm/rsg_e6_05p03.htm', hinweis: 'Eröffnung: Art. 19A (ca. 250 CHF).', regel: { typ: 'rahmen', vonChf: 200, bisChf: 2000 } },
    JU: { kanton: 'JU', erlassName: 'Décret concernant les émoluments des notaires du 6 décembre 1978', erlassNr: 'RSJU 189.61', artikel: 'Art. 12 al. 1', stand: '01.01.2007', verifiziert: R, quelleUrl: 'https://rsju.jura.ch/fr/viewdocument.html?idn=20029&id=37829&download=1', hinweis: 'Im JU-Tarif wertbasiert (nicht fix), aber bei max. 2\'000 CHF gedeckelt. Nebenleistungen/Beratung Art. 6 separat.', regel: { typ: 'rahmen', vonChf: 200, bisChf: 2000 } },
