    GR: { kanton: 'GR', erlassName: 'Verordnung über die Notariatsgebühren (NotGebV)', erlassNr: 'BR 210.370', artikel: 'Art. 10 Abs. 1 lit. a NotGebV (Beglaubigung); Beurkundung ggf. Art. 7', stand: '1. Januar 2024', verifiziert: R, quelleUrl: 'https://www.gr-lex.gr.ch/api/de/versions/3348/pdf_file', hinweis: 'Fr. 30 gilt für die Unterschriftsbeglaubigung; bei fremdsprachiger Urkunde/Zeugen/Übersetzer bis zum doppelten Betrag (Art. 10 Abs. 2). Beurkundung einer Vollmacht ohne eigene Position -> Aufwand Art. 7.', regel: { typ: 'fix', chf: 30 } },
    AG: { kanton: 'AG', erlassName: 'Dekret über den Notariatstarif', erlassNr: 'SAR 295.250', artikel: '§ 6 Abs. 1 lit. a (Beglaubigung) bzw. § 1 (Aufwandtarif bei Beurkundung)', stand: '01.01.2025', verifiziert: R, quelleUrl: 'https://gesetzessammlungen.ag.ch/api/de/texts_of_law/295.250', hinweis: 'Fixbetrag Fr. 20.- gilt für die Unterschriftsbeglaubigung. Bei eigentlicher Beurkundung der Vollmacht: Aufwandtarif § 1. Plus MwSt/Auslagen (§ 9).', regel: { typ: 'fix', chf: 20 } },
    TG: { kanton: 'TG', erlassName: 'Gesetz über die Gebühren und Gemengsteuern der Grundbuchämter und Notariate (GGG)', erlassNr: 'RB 632.1', artikel: '§ 16 GGG; § 7/§ 19 GGG (Beglaubigung)', stand: '01.01.2016', verifiziert: R, quelleUrl: 'https://www.rechtsbuch.tg.ch/api/de/texts_of_law/632.1', hinweis: 'Blosse Beglaubigung: nicht § 16, sondern Verordnung des Regierungsrats (§ 7/§ 19, max Fr. 2\'000). Konkreter Beglaubigungsfixbetrag steht nicht im Gesetz.', regel: { typ: 'formel_extern', hinweis: 'Wird eine Vollmacht oeffentlich beurkundet, gilt § 16 (Fr. 200 bis Fr. 10\'000 nach Aufwand). Reine Unterschriften-/Beglaubigung ist keine oeffentliche Beurkundung i.S.v. § 16; dafuer legt der Regieru' } },
