    VD: { kanton: 'VD', erlassName: 'Tarif des honoraires dus aux notaires pour des opérations ministérielles (TNo)', erlassNr: 'BLV 178.11.2', artikel: 'Art. 30 TNo (procuration instrumentée en brevet); Art. 29 pour légalisation de signature', stand: '01.03.2016', verifiziert: R, quelleUrl: 'https://prestations.vd.ch/pub/blv-publication/actes/consolide/178.11.2?id=26c09c57-9d81-4ec3-a442-e33bc904027b', hinweis: 'Cadre fixe Fr. 20-500 (acte en brevet, Art. 30) ou Fr. 20-50 si simple légalisation de signature (Art. 29).', regel: { typ: 'rahmen', vonChf: 20, bisChf: 500 } },
    VS: { kanton: 'VS', erlassName: 'Règlement fixant le tarif des émoluments et des débours des notaires', erlassNr: '178.104', artikel: 'Art. 16 al. 1 lit. i ch. 12 / ch. 13 (procuration); ch. 11 (légalisation de signature)', stand: '26.11.2008', verifiziert: R, quelleUrl: 'https://lex.vs.ch/api/fr/versions/1413/pdf_file', hinweis: 'fixChf=30 betrifft die Unterschriftsbeglaubigung; Vollmacht authentique 40-400, schriftlich 15-150.', regel: { typ: 'rahmen', vonChf: 15, bisChf: 400 } },
