    AI: { kanton: 'AI', erlassName: 'Gebührentarif (GebT)', erlassNr: 'GS 172.513', artikel: 'Art. 14 Abs. 3 Ziff. 1 GebT', stand: '2026-01-01', verifiziert: R, quelleUrl: 'https://ai.clex.ch/app/de/texts_of_law/172.513', hinweis: 'Gemeinsame Position \'Gründung\' für AG und GmbH; keine Differenzierung nach Rechtsform oder Kapitalhöhe.', regel: { typ: 'rahmen', vonChf: 400, bisChf: 4000 } },
