    GR: { kanton: 'GR', erlassName: 'Verordnung über die Notariatsgebühren (NotGebV)', erlassNr: 'BR 210.370', artikel: 'Art. 17 Abs. 1 lit. a NotGebV', stand: '1. Januar 2024', verifiziert: R, quelleUrl: 'https://www.gr-lex.gr.ch/api/de/versions/3348/pdf_file', hinweis: '1‰ nur auf den 200\'000 übersteigenden Teil des Aktienkapitals (inkl. Agio als Teil des Kapitalwerts); kein expliziter Höchstbetrag. Sacheinlage zusätzlich nach Sachenrechtstarif.', regel: { typ: 'promille', promille: 1, minChf: 1000 } },
    AG: { kanton: 'AG', erlassName: 'Dekret über den Notariatstarif', erlassNr: 'SAR 295.250', artikel: '§ 1 (Aufwandtarif)', stand: '01.01.2025', verifiziert: R, quelleUrl: 'https://gesetzessammlungen.ag.ch/api/de/texts_of_law/295.250', hinweis: 'Kein Werttarif auf Aktienkapital/Agio. Plus MwSt/Auslagen (§ 9).', regel: { typ: 'formel_extern', hinweis: 'Errichtungsakt AG ist nicht vom Promilletarif (§ 2, nur Grundstücke/Baurechte) erfasst. Abrechnung nach Aufwandtarif, Stundenansatz höchstens Fr. 300.- (§ 1).' } },
    TG: { kanton: 'TG', erlassName: 'Gesetz über die Gebühren und Gemengsteuern der Grundbuchämter und Notariate (GGG)', erlassNr: 'RB 632.1', artikel: '§ 16 GGG', stand: '01.01.2016', verifiziert: R, quelleUrl: 'https://www.rechtsbuch.tg.ch/api/de/texts_of_law/632.1', hinweis: 'Bei besonderer Verantwortung Erhoehung moeglich (§ 16 Abs. 3).', regel: { typ: 'formel_extern', hinweis: 'Errichtungsakt AG (Art. 629 OR) ist oeffentliche Beurkundung nach § 16: Fr. 200 bis Fr. 10\'000 pro Geschaeft nach Arbeits-/Zeitaufwand und Bedeutung des Geschaefts. KEIN wertbasierter Tarif auf Aktie' } },
